#!/usr/bin/env python3
"""
benchmark_generator.py
Generate XCTest performance benchmarks for iOS/macOS projects.

Usage:
  python benchmark_generator.py --target MyApp --output ./benchmarks --name ParsingBench --operation "JSON decode 10k rows"

It emits a Swift file with a test case using measure(metrics:).
"""
import argparse, os, textwrap, datetime, json

TEMPLATE = """\
// Auto-generated by benchmark_generator.py on {date}
import XCTest

final class {name}Tests: XCTestCase {{
    override class var defaultMeasureOptions: XCTMeasureOptions {{
        let opts = XCTMeasureOptions()
        opts.iterationCount = 5
        return opts
    }}

    func test_{slug}_clock_cpu_memory() throws {{
        let payloadURL = Bundle.module.url(forResource: "payload", withExtension: "json")!
        let data = try Data(contentsOf: payloadURL)

        measure(metrics: [XCTClockMetric(), XCTCPUMetric(), XCTMemoryMetric()]) {{
            // BEGIN operation under test
            var decodedCount = 0
            do {{
                let obj = try JSONSerialization.jsonObject(with: data) as? [[String:Any]]
                decodedCount = obj?.count ?? 0
            }} catch {{
                XCTFail("decode failed: \\(error)")
            }}
            XCTAssertGreaterThan(decodedCount, 0)
            // END operation under test
        }}
    }}

    func test_{slug}_signposted() throws {{
        let app = XCUIApplication()
        app.launch()
        measure(metrics: [XCTOSSignpostMetric.scrollingAndDeceleration, XCTApplicationLaunchMetric()]) {{
            // Place signpost-backed UI scenario here, e.g., scroll a feed
            // XCTOSSignpostMetric is available for UI tests measuring UI animations
        }}
    }}
}}
"""

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--target", required=True, help="Xcode target name")
    ap.add_argument("--output", required=True, help="Output folder for the Swift test")
    ap.add_argument("--name", required=True, help="Benchmark name class prefix")
    ap.add_argument("--operation", required=True, help="Short description of the benchmarked operation")
    args = ap.parse_args()

    os.makedirs(args.output, exist_ok=True)
    slug = "".join(c if c.isalnum() else "_" for c in args.operation.lower()).strip("_")
    swift_name = f"{args.name}PerformanceTests.swift"
    content = TEMPLATE.format(date=datetime.datetime.utcnow().isoformat()+"Z", name=args.name, slug=slug)
    out_path = os.path.join(args.output, swift_name)
    with open(out_path, "w") as f:
        f.write(content)
    meta = { "target": args.target, "name": args.name, "operation": args.operation, "file": swift_name }
    with open(os.path.join(args.output, f"{args.name}.json"), "w") as jf:
        json.dump(meta, jf, indent=2)
    print(f"[ok] Wrote {out_path}")

if __name__ == "__main__":
    main()
